INSERT INTO `news` (`id`, `title`, `text`, `picture`, `category_id`, `user_id`) VALUES
(1, 'Koroonaviiruse läbi põdenud Alev loodab Rukal löögihoos olla.', '32-aastane Eesti murdmaasuusataja Alvar Johannes Alev oli hooaja avavõistlusel Beitostølenis ootamatult kahvatu – seda põhjusel, et teda vedasid alt suusad ja hiljuti põdes sportlane (suure tõenäosusega) läbi koroonaviiruse.', , 3, 1);
INSERT INTO `news` (`id`, `title`, `text`, `picture`, `category_id`, `user_id`) VALUES
(2, 'Taylor Swift võttis muusikavideo filmimiseks ette salajase reisi. Osaliselt ostukeskuses filmitud video eelarveks on väidetavalt miljon naela', 'Ühendkuningriigi meedia kihab sellest, kuidas popstaar Taylor Swift tegi eelmisel nädalal Ameerika Ühendriikidest salajase reisi üle ookeani, et Suurbritannias võtta linti oma uus muusikavideo. Laulja viibis riigis pea nädala, kuid sel ajal õnnestus tal jääda mitte ühelegi pildile ega videole.', , 2, 1);
INSERT INTO `news` (`id`, `title`, `text`, `picture`, `category_id`, `user_id`) VALUES
(3, '„Nii ebaõiglane, kutsun protestima!“ Televaatajad pole rahul näosaate finalistidega', 'Eile õhtul eetrisse läinud „Su nägu kõlab tuttavalt“ saates selgusid neli finalisti. Kaheksa saate peale kogusid enim punkte ning kindlustasid omale pääsu finaali vaid saate naissoost osalised, mis tekitas televaatajates suurt pettumust.', , 1, 1);
INSERT INTO `news` (`id`, `title`, `text`, `picture`, `category_id`, `user_id`) VALUES
(4, 'INTERVJUU | LHV Groupi uus juht Mihkel Torim: neopangad võivad siseneda laenuturule. Peame selleks valmis olema', 'LHV peahoone kõrval käib vilgas ehitustegevus. Öeldakse, et kui kraanad on püsti, siis läheb majandusel hästi. Magnaadile antud intervjuus räägime Mihkel Torimiga nii sellest, on kas nii, kui ka sellest, mida teeb tippjuht, kui pangaukse enda selja taga sulgeb. Naljapäeval saadud kõne Rain Lõhmuselt keeras tema elus kevadel uue lehekülje.', , 1, 1);

